def test_transpose_matrix():
    A = [[1, 2, 3],
         [4, 5, 6],
         [7, 8, 9]]
    
    expected = [[1, 4, 7],
                [2, 5, 8],
                [3, 6, 9]]
    
    result = transpose_matrix(A)
    assert result == expected
    
    A2 = [[1, 2], 
          [3, 4]]
    expected2 = [[1, 3], 
                 [2, 4]]
    
    assert transpose_matrix(A2) == expected2

def test_transpose_matrix_ml_kem_768():
    A_bytes = bytes.fromhex("")
    AT_expected_bytes = bytes.fromhex("")
    
    k = 3
    poly_len = 384
    
    A = []
    for i in range(k):
        row = []
        for j in range(k):
            start = (i * k + j) * poly_len
            poly_coeffs = byte_decode(A_bytes[start:start+poly_len], 12)
            row.append(poly_coeffs)
        A.append(row)
    
    AT_calculated = transpose_matrix(A)
    
    AT_calculated_bytes = b""
    for i in range(k):
        for j in range(k):
            AT_calculated_bytes += byte_encode(AT_calculated[i][j], 12)
    
    assert AT_calculated_bytes == AT_expected_bytes

def test_bytes_to_bits():
    test_bytes = bytes([0b10110010])  # 0xb2
    expected_bits = [0, 1, 0, 0, 1, 1, 0, 1]  # LSB first
    result = bytes_to_bits(test_bytes)
    assert result == expected_bits

def test_bits_to_bytes():
    test_bits = [1, 0, 1, 1, 0, 0, 0, 0,  # 0x0d LSB first
                 0, 0, 0, 0, 0, 0, 0, 0,  # 0x00
                 1, 0, 1, 1, 0, 0, 0, 0]  # 0x0d LSB first
    expected_bytes = [0x0d, 0x00, 0x0d]
    result = bits_to_bytes(test_bits)
    assert result == expected_bytes

def test_encode_decode_roundtrip():
    data = [1] * 256
    encoded = byte_encode(data, 12)
    decoded = byte_decode(encoded, 12)

    print(len(decoded))   # nur zum Debuggen
    assert len(decoded) == 256
    assert decoded == data